@Injectable()
export class ConfigurableLoggingInterceptor implements NestInterceptor {
  constructor(private readonly includeInterceptorTime: boolean = false) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const startTime = Date.now();
    return next.handle().pipe(
      tap(() => {
        const duration = Date.now() - startTime;
        const message = this.includeInterceptorTime
          ? `Requête + transformations: ${duration}ms`
          : `Handler uniquement: ${duration}ms`;
        console.log(message);
      }),
    );
  }
}

// Utilisation dans un module avec injection
@Module({
  providers: [
    {
      provide: APP_INTERCEPTOR,
      useClass: TransformInterceptor,
    },
    {
      provide: APP_INTERCEPTOR,
      useFactory: () => new ConfigurableLoggingInterceptor(false),
    },
  ],
})
export class AppModule {}
```
Avec cette configuration, l'interceptor de logging (extérieur) mesurera le temps total incluant la transformation. Placer LoggingInterceptor en premier le fera mesurer handler + transformations.
